let intoArray = string13.split(' ')

console.log(intoArray) //[ 'Days', 'Of', 'JavaScript' ]
console.log(string12.concat(intoArray[0], intoArray[1], intoArray[2])) 

let string15 = '30'
console.log(string15.concat("Days", "Of", "JavaScript")) // 30DaysOfJavaScript

